public class MyControl : UserControl
{
    public string DisplayName { get; set; }
    public int MaxItems { get; set; }

    // .NET 9 breaking change: StatusStrip now defaults to ToolStripSystemRenderer.
    // Explicitly set ManagerRenderMode to preserve the .NET 8 professional look.
    private readonly StatusStrip _statusStrip = new StatusStrip
    {
        RenderMode = ToolStripRenderMode.ManagerRenderMode
    };

    public MyControl()
    {
        _statusStrip.Items.Add(new ToolStripStatusLabel("Ready"));
        Controls.Add(_statusStrip);
    }
}

public class SafeDropDownEditor : UITypeEditor
{
    public override object EditValue(
        System.ComponentModel.ITypeDescriptorContext context,
        IServiceProvider provider,
        object value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;

        if (editorService is null)
            return value;

        // .NET 9 breaking change: DropDownControl now throws ArgumentNullException
        // when passed null. Guard against it.
        var control = CreateDropDown(value);
        if (control is not null)
        {
            editorService.DropDownControl(control);
            value = GetValueFromControl(control);
        }

        return value;
    }

    private Control? CreateDropDown(object value) => new ListBox();
    private object GetValueFromControl(Control control) => ((ListBox)control).SelectedItem;

    public override UITypeEditorEditStyle GetEditStyle(
        System.ComponentModel.ITypeDescriptorContext context)
        => UITypeEditorEditStyle.DropDown;
}

